const body = $input.first().json.body;

// TikTok Shop webhook types
const type = body.type || '';

// Only process new/paid orders
if (!['ORDER_STATUS_CHANGE', '141'].includes(String(type))) {
  return [{ json: { skip: true, reason: 'not an order event' } }];
}

const data = body.data || {};
const order = data.order_info || data || {};

// Map TikTok fields → BabyKawaii fields
const recipient = order.recipient_address || {};
const lineItems = order.line_items || [];

const items = lineItems.map(item => ({
  tiktok_sku_id:  item.sku_id || '',
  seller_sku:     item.seller_sku || '',     // ต้อง map กับ BabyKawaii SKU
  product_name:   item.product_name || '',
  size:           item.sku_name?.split('/')[0]?.trim() || '',
  color:          item.sku_name?.split('/')[1]?.trim() || '',
  quantity:       item.quantity || 1,
  unit_price:     parseFloat(item.sale_price || 0)
}));

return [{ json: {
  skip: false,
  tiktok_order_id: order.order_id || order.id || '',
  customer_name:   recipient.name || order.buyer_username || 'ลูกค้า TikTok',
  customer_phone:  recipient.phone_number || '',
  customer_address: [
    recipient.address_line1,
    recipient.address_line2,
    recipient.district_info?.district_name,
    recipient.district_info?.province_name,
    recipient.zipcode
  ].filter(Boolean).join(' '),
  shipping_fee:   parseFloat(order.shipping_fee || 50),
  items
}}];

// TikTok seller_sku ควรตั้งให้ตรงกับ BabyKawaii SKU เช่น BK-001-W-NB
// ถ้าไม่ตรง: admin จะเห็นออเดอร์ใน system แต่ product_id = 0 (ต้องแก้ manual)
const data = $input.first().json;

const mappedItems = data.items.map(item => {
  // seller_sku format: BK-001-W-NB (sku-colorEn-size)
  const parts = (item.seller_sku || '').split('-');
  // ถ้า SKU format ถูกต้อง: parts[0]+parts[1] = base SKU (BK-001)
  return {
    ...item,
    // product_id จะถูก resolve โดย orders API จาก SKU
    resolved_sku: item.seller_sku || item.product_name
  };
});

return [{ json: { ...data, items: mappedItems } }];

